db = SessionLocal()

try:
    existing = db.query(Shop).count()
    if existing > 0:
        print(f"Database already has {existing} shops. Skipping seed.")
    else:
        shops = [Shop(**data) for data in SAMPLE_SHOPS]
        db.add_all(shops)
        db.commit()
        print(f"Seeded {len(SAMPLE_SHOPS)} shops successfully.")
except Exception as e:
    db.rollback()
    print(f"Seed failed: {e}")
finally:
    db.close()
